// ############################################################################//
//                                                                             //
//    ... restart z2m to apply the converter                                   //
//                                                                             //
//#############################################################################//

const {
    numeric,
    binary,
    co2,
    pressure,
    temperature,
    humidity,
    reporting,
    identify,
} = require('zigbee-herdsman-converters/lib/modernExtend');

const fourReporting = {min: 20, max: 1200, change: 15};
const fiveReporting = {min: 60, max: 1800, change: 1};
const co2Reporting = {min: 20, max: 600, change: 0.000001};
const ch20Reporting = {min: 20, max: 600, change: 0.001};

const definition = {
    zigbeeModel: ["DIYRuZ_AirSense_Reloaded"],
    model: "DIYRuZ_AirSense_Reloaded",
    vendor: "EfektaLab",
    description: "Air quality sensor (CO2, formaldehyde, temperature, humidity, pressure)",
    icon: 'data:image/png;base64,',
    extend: [
        identify(),

        // CO2 sensor
        co2({
            reporting: co2Reporting,
            access: "STATE_GET",
        }),

        // Formaldehyde (CH2O)
        numeric({
            name: "formaldehyde_concentration",
            unit: "ppm",
            cluster: "msFormaldehyde",
            attribute: "measuredValue",
            description: "Formaldehyde (CH2O) concentration",
            access: "STATE_GET",
            reporting: ch20Reporting,
        }),

        // Temperature
        temperature({
            reporting: fourReporting,
            access: "STATE_GET",
        }),

        // Atmospheric pressure
        pressure({
            reporting: fiveReporting,
            access: "STATE_GET",
        }),

        // Humidity
        humidity({
            reporting: fourReporting,
            access: "STATE_GET",
        }),

        // Accurate CO2 measurement mode
        binary({
            name: "co2_accurate_measurement",
            valueOn: ["ON", 1],
            valueOff: ["OFF", 0],
            cluster: "msCO2",
            attribute: {ID: 0xF111, type: 0x10},
            description: "Enable/disable accurate CO2 measurement mode",
            access: "ALL",
        }),

        // Automatic CO2 calibration
        binary({
            name: "co2_automatic_calibration",
            valueOn: ["ON", 1],
            valueOff: ["OFF", 0],
            cluster: "msCO2",
            attribute: {ID: 0x0202, type: 0x10},
            description: "Enable/disable automatic calibration of CO2 sensor",
            access: "ALL",
        }),

        // LED indication
        binary({
            name: "led_indication",
            valueOn: ["ON", 1],
            valueOff: ["OFF", 0],
            cluster: "msCO2",
            attribute: {ID: 0x0203, type: 0x10},
            description: "Enable/disable LED indication",
            access: "ALL",
        }),

        // Moderate CO2 threshold
        numeric({
            name: "co2_moderate_threshold",
            unit: "ppm",
            valueMin: 0,
            valueMax: 5000,
            valueStep: 1,
            cluster: "msCO2",
            attribute: {ID: 0x0204, type: 0x21},
            description: "Threshold for moderate CO2 level",
            access: "ALL",
        }),

        // Hazardous CO2 threshold
        numeric({
            name: "co2_hazardous_threshold",
            unit: "ppm",
            valueMin: 0,
            valueMax: 5000,
            valueStep: 1,
            cluster: "msCO2",
            attribute: {ID: 0x0205, type: 0x21},
            description: "Threshold for hazardous CO2 level",
            access: "ALL",
        }),

        // Moderate formaldehyde threshold
        numeric({
            name: "formaldehyde_moderate_threshold",
            unit: "ppb",
            valueMin: 0,
            valueMax: 5000,
            valueStep: 1,
            cluster: "msFormaldehyde",
            attribute: {ID: 0x0204, type: 0x21},
            description: "Threshold for moderate formaldehyde (CH2O) level",
            access: "ALL",
        }),

        // Hazardous formaldehyde threshold
        numeric({
            name: "formaldehyde_hazardous_threshold",
            unit: "ppb",
            valueMin: 0,
            valueMax: 5000,
            valueStep: 1,
            cluster: "msFormaldehyde",
            attribute: {ID: 0x0205, type: 0x21},
            description: "Threshold for hazardous formaldehyde (CH2O) level",
            access: "ALL",
        }),

        // Temperature offset
        numeric({
            name: "temperature_offset",
            unit: "°C",
            valueMin: -20,
            valueMax: 20,
            valueStep: 0.1,
            scale: 10,
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0210, type: 0x29},
            description: "Temperature calibration offset",
            access: "ALL",
        }),

        // Humidity offset
        numeric({
            name: "humidity_offset",
            unit: "%",
            valueMin: -50,
            valueMax: 50,
            valueStep: 1,
            cluster: "msRelativeHumidity",
            attribute: {ID: 0x0210, type: 0x29},
            description: "Humidity calibration offset",
            access: "ALL",
        }),

        // Pressure offset
        numeric({
            name: "pressure_offset",
            unit: "hPa",
            valueMin: -1000,
            valueMax: 1000,
            valueStep: 1,
            cluster: "msPressureMeasurement",
            attribute: {ID: 0x0210, type: 0x2b},
            description: "Pressure calibration offset",
            access: "ALL",
        }),

        // Formaldehyde offset (ADC range)
        numeric({
            name: "formaldehyde_offset",
            unit: "adc",
            valueMin: -100,
            valueMax: 100,
            valueStep: 1,
            cluster: "msFormaldehyde",
            attribute: {ID: 0x0210, type: 0x28},
            description: "Formaldehyde ADC range calibration offset",
            access: "STATE_SET",
        }),
    ],
};

module.exports = definition;